1	import Link from "next/link";
2	import { notFound, redirect } from "next/navigation";
3	import { revalidatePath } from "next/cache";
4	import { db } from "@/lib/db";
5	import { resolveClaimTexts } from "@/lib/api/round3";
6	import { founderDisplayName } from "@/lib/founderDisplay";
7	import {
8	  mqsForConclusion,
9	  profilesForConclusions,
10	  type PublicationMethodologyProfile,
11	} from "@/lib/methodologyProfiles";
12	import { canWrite } from "@/lib/roles";
13	import { requireTenantContext } from "@/lib/tenant";
14	import PageHelp from "@/components/PageHelp";
15	import PublishToggle from "@/components/PublishToggle";
16	import TabNav from "@/components/TabNav";
17	import PublicationClient from "../../publication/PublicationClient";
18	import ConclusionSigil from "./conclusion-sigil";
19	import ProvenanceTab from "./provenance-tab";
20	import CascadeTab from "./cascade-tab";
21	import PeerReviewTab from "./peer-review-tab";
22	import BlindspotsPanel from "./BlindspotsPanel";
23	import RelatedTab from "./related-tab";
24	import HistoryTab from "./history-tab";
25	import LineagePanel from "./LineagePanel";
26	import ActionsBar from "./actions-bar";
27	import ConclusionKeymap from "./conclusion-keymap";
28	import MqsCard from "./MqsCard";
29	import FailureModesCard from "./FailureModesCard";
30	import { matchModesForConclusion } from "@/lib/failureModes";
31	
32	/**
33	 * Single-conclusion detail page.
34	 *
35	 * Tabs: Overview | Provenance | Cascade | Peer review. Tab state is
36	 * carried in `?tab=…` so URLs remain shareable.
37	 */
38	
39	const TABS = [
40	  { id: "overview", label: "Overview" },
41	  { id: "provenance", label: "Provenance" },
42	  { id: "cascade", label: "Cascade" },
43	  { id: "peer", label: "Peer review" },
44	  { id: "blindspots", label: "Geometric blindspots" },
45	  { id: "related", label: "Related" },
46	  { id: "lineage", label: "Lineage" },
47	  { id: "history", label: "History" },
48	] as const;
49	
50	type TabId = (typeof TABS)[number]["id"];
51	
52	function isTabId(value: string | undefined): value is TabId {
53	  return TABS.some((t) => t.id === value);
54	}
55	
56	// Confidence-tier thresholds — kept near the UI that uses them so a
57	// reader lands on the same numbers that appear in the rendered tooltip.
58	// Mirrors the semantic bands described in noosphere ConfidenceTier.
59	const TIER_THRESHOLDS: Array<{ tier: string; min: number; color: string }> = [
60	  { tier: "firm", min: 0.85, color: "var(--gold)" },
61	  { tier: "founder", min: 0.65, color: "var(--amber)" },
62	  { tier: "open", min: 0.30, color: "var(--parchment)" },
63	  { tier: "speculative", min: 0, color: "var(--parchment-dim)" },
64	];
65	
66	function tryParse(raw: string): string[] {
67	  try {
68	    const v = JSON.parse(raw);
69	    return Array.isArray(v) ? v.map(String) : [];
70	  } catch {
71	    return [];
72	  }
73	}
74	
75	export default async function ConclusionDetailPage({
76	  params,
77	  searchParams,
78	}: {
79	  params: Promise<{ id: string }>;
80	  searchParams: Promise<{ tab?: string; queued?: string; deletionRequested?: string }>;
81	}) {
82	  const tenant = await requireTenantContext();
83	  if (!tenant) {
84	    return null;
85	  }
86	
87	  const { id } = await params;
88	  const sp = await searchParams;
89	  const activeTab: TabId = isTabId(sp.tab) ? sp.tab : "overview";
90	
91	  const [conclusion, publicationReviews, publishedVersions] = await Promise.all([
92	    db.conclusion.findFirst({
93	      where: { id, organizationId: tenant.organizationId },
94	      include: {
95	        attributedFounder: true,
96	        organization: true,
97	        // Source uploads: the M:N bridge row plus the underlying Upload
98	        // metadata we need for the "Source documents" list in the Overview
99	        // tab and the inline source publish toggles below. Filtered in app
100	        // code to drop uploads that have been soft-deleted since extraction.
101	        sources: {
102	          include: {
103	            upload: {
104	              select: {
105	                id: true,
106	                title: true,
107	                sourceType: true,
108	                status: true,
109	                visibility: true,
110	                founderId: true,
111	                publishedAt: true,
112	                slug: true,
113	                createdAt: true,
114	                deletedAt: true,
115	              },
116	            },
117	          },
118	          orderBy: { createdAt: "desc" },
119	        },
120	      },
121	    }),
122	    db.publicationReview.findMany({
123	      where: { organizationId: tenant.organizationId, conclusionId: id },
124	      orderBy: { updatedAt: "desc" },
125	      take: 20,
126	      include: {
127	        target: true,
128	        reviewer: {
129	          select: { id: true, displayName: true, name: true, username: true },
130	        },
131	      },
132	    }),
133	    db.publishedConclusion.findMany({
134	      where: { organizationId: tenant.organizationId, sourceConclusionId: id },
135	      orderBy: { version: "desc" },
136	      take: 10,
137	      select: {
138	        id: true,
139	        slug: true,
140	        version: true,
141	        publishedAt: true,
142	        doi: true,
143	      },
144	    }),
145	  ]);
146	  if (!conclusion) notFound();
147	
148	  const supportIds = tryParse(conclusion.supportingPrincipleIds);
149	  const evidenceIds = tryParse(conclusion.evidenceChainClaimIds);
150	  const dissentIds = tryParse(conclusion.dissentClaimIds);
151	
152	  // Batch one lookup for every ID across all three arrays — the helper
153	  // queries the Conclusion table by id, returns a Record<id, text>.
154	  // IDs that don't resolve are displayed as opaque IDs with a note.
155	  const allIds = [...supportIds, ...evidenceIds, ...dissentIds];
156	  const idTextMap = await resolveClaimTexts(tenant.organizationId, allIds);
157	
158	  const sourceUploads = conclusion.sources
159	    .filter((cs) => !cs.upload.deletedAt)
160	    .map((cs) => ({
161	      uploadId: cs.upload.id,
162	      title: cs.upload.title,
163	      sourceType: cs.upload.sourceType,
164	      status: cs.upload.status,
165	      visibility: cs.upload.visibility,
166	      founderId: cs.upload.founderId,
167	      publishedAt: cs.upload.publishedAt,
168	      slug: cs.upload.slug,
169	    }));
170	  const sources = sourceUploads.map((source) => ({
171	    uploadId: source.uploadId,
172	    title: source.title,
173	    sourceType: source.sourceType,
174	  }));
175	  const writer = canWrite(tenant.role);
176	  const methodologyProfiles =
177	    (await profilesForConclusions(tenant.organizationId, [conclusion.id])).get(conclusion.id) ?? [];
178	  const mqs = await mqsForConclusion(tenant.organizationId, conclusion.id);
179	  const conclusionMethods = await db.conclusionMethod.findMany({
180	    where: { organizationId: tenant.organizationId, conclusionId: conclusion.id },
181	    select: { methodName: true },
182	  });
183	  const matchedFailureModes = matchModesForConclusion(
184	    conclusionMethods.map((m) => m.methodName),
185	    conclusion.text,
186	  );
187	  const publicationReviewProps = publicationReviews.map((r) => ({
188	    id: r.id,
189	    status: r.status,
190	    checklistJson: r.checklistJson,
191	    reviewerNotes: r.reviewerNotes,
192	    declineReason: r.declineReason,
193	    revisionAsk: r.revisionAsk,
194	    reviewerFounderId: r.reviewerFounderId,
195	    createdAt: r.createdAt.toISOString(),
196	    updatedAt: r.updatedAt.toISOString(),
197	    target: {
198	      id: r.target.id,
199	      text: r.target.text,
200	      topicHint: r.target.topicHint,
201	      confidenceTier: r.target.confidenceTier,
202	      confidence: r.target.confidence,
203	      createdAt: r.target.createdAt.toISOString(),
204	      methodologyProfiles,
205	    },
206	    reviewer: r.reviewer,
207	  }));
208	  const firmConclusionProps =
209	    conclusion.confidenceTier === "firm"
210	      ? [
211	          {
212	            id: conclusion.id,
213	            text: conclusion.text,
214	            topicHint: conclusion.topicHint,
215	            createdAt: conclusion.createdAt.toISOString(),
216	            methodologyProfiles,
217	          },
218	        ]
219	      : [];
220	  const toggleableSourceUploads = sourceUploads.filter(
221	    (source) =>
222	      writer &&
223	      source.status === "ingested" &&
224	      (tenant.role === "admin" || source.founderId === tenant.founderId),
225	  );
226	
227	  async function requestConclusionDeletion(formData: FormData) {
228	    "use server";
229	    const cid = String(formData.get("conclusionId") || "");
230	    if (!cid) return;
231	    const t = await requireTenantContext();
232	    if (!t) redirect("/login");
233	    // Prevent a dup pending request from the same founder.
234	    const existing = await db.conclusionDeletionRequest.findFirst({
235	      where: { conclusionId: cid, requesterId: t.founderId, status: "pending" },
236	      select: { id: true },
237	    });
238	    if (!existing) {
239	      await db.conclusionDeletionRequest.create({
240	        data: {
241	          conclusionId: cid,
242	          requesterId: t.founderId,
243	          reason: "Requested from conclusion detail page",
244	        },
245	      });
246	      await db.auditEvent.create({
247	        data: {
248	          organizationId: t.organizationId,
249	          founderId: t.founderId,
250	          action: "conclusion_deletion_request",
251	          detail: JSON.stringify({ conclusionId: cid, source: "detail-page" }),
252	        },
253	      });
254	    }
255	    revalidatePath(`/conclusions/${cid}`);
256	    redirect(`/conclusions/${cid}?deletionRequested=1`);
257	  }
258	
259	  return (
260	    <main style={{ padding: "2rem 0" }}>
261	      <ConclusionKeymap conclusionId={id} canPublish={writer} />
262	      <PageHelp
263	        title="Conclusion"
264	        purpose={`"${conclusion.text.slice(0, 140)}${conclusion.text.length > 140 ? "…" : ""}"`}
265	        howTo="The tabs below show everything the system knows about this conclusion: its origin (Provenance), its downstream consequences (Cascade), and peer reactions to it (Peer review)."
266	        sigil={<ConclusionSigil />}
267	      />
268	
269	      <div style={{ maxWidth: "1200px", margin: "0 auto", padding: "0 1.5rem" }}>
270	        {sp.queued && (
271	          <div
272	            className="portal-card"
273	            style={{
274	              padding: "0.6rem 1rem",
275	              marginBottom: "1rem",
276	              borderLeft: "3px solid var(--gold)",
277	              fontSize: "0.8rem",
278	              color: "var(--gold)",
279	            }}
280	          >
281	            Queued for publication review.
282	          </div>
283	        )}
284	
285	        <header style={{ marginBottom: "1.5rem" }}>
286	          <div
287	            style={{
288	              display: "flex",
289	              alignItems: "baseline",
290	              gap: "1rem",
291	              flexWrap: "wrap",
292	            }}
293	          >
294	            <span
295	              style={{
296	                fontFamily: "'Cinzel', serif",
297	                fontSize: "0.65rem",
298	                letterSpacing: "0.15em",
299	                textTransform: "uppercase",
300	                padding: "0.2rem 0.6rem",
301	                border: "1px solid var(--gold-dim)",
302	                color: "var(--gold)",
303	                borderRadius: 2,
304	              }}
305	            >
306	              {conclusion.confidenceTier}
307	            </span>
308	            <span
309	              style={{
310	                fontSize: "0.75rem",
311	                color: "var(--parchment-dim)",
312	              }}
313	            >
314	              Confidence {(conclusion.confidence * 100).toFixed(0)}%
315	              {conclusion.attributedFounder
316	                ? ` · Attributed to ${founderDisplayName(conclusion.attributedFounder)}`
317	                : ""}
318	              {conclusion.topicHint ? ` · ${conclusion.topicHint}` : ""}
319	            </span>
320	          </div>
321	
322	          <ConfidenceContext confidence={conclusion.confidence} />
323	
324	          {conclusion.rationale ? (
325	            <p
326	              style={{
327	                marginTop: "0.75rem",
328	                fontSize: "0.95rem",
329	                color: "var(--parchment)",
330	                fontStyle: "italic",
331	              }}
332	            >
333	              Rationale: {conclusion.rationale}
334	            </p>
335	          ) : null}
336	        </header>
337	
338	        <PublicationInlinePanel
339	          canUseReviewControls={writer}
340	          currentFounderId={tenant.founderId}
341	          firmConclusions={firmConclusionProps}
342	          publishedVersions={publishedVersions.map((version) => ({
343	            ...version,
344	            publishedAt: version.publishedAt.toISOString(),
345	          }))}
346	          reviews={publicationReviewProps}
347	          sourceUploads={toggleableSourceUploads}
348	        />
349	
350	        {mqs ? <MqsCard mqs={mqs} /> : null}
351	
352	        <FailureModesCard
353	          conclusionId={conclusion.id}
354	          matched={matchedFailureModes}
355	        />
356	
357	        <ActionsBar conclusionId={id} />
358	
359	        <TabNav
360	          basePath={`/conclusions/${id}`}
361	          current={activeTab}
362	          tabs={TABS as unknown as ReadonlyArray<{ id: string; label: string }>}
363	        />
364	
365	        <section style={{ marginTop: "1.5rem" }}>
366	          {activeTab === "overview" ? (
367	            <OverviewTab
368	              text={conclusion.text}
369	              supportIds={supportIds}
370	              evidenceIds={evidenceIds}
371	              dissentIds={dissentIds}
372	              idTextMap={idTextMap}
373	              sources={sources}
374	            />
375	          ) : activeTab === "provenance" ? (
376	            <ProvenanceTab conclusionId={id} />
377	          ) : activeTab === "cascade" ? (
378	            <CascadeTab conclusionId={id} />
379	          ) : activeTab === "peer" ? (
380	            <PeerReviewTab conclusionId={id} />
381	          ) : activeTab === "blindspots" ? (
382	            <BlindspotsPanel
383	              conclusionId={id}
384	              organizationId={tenant.organizationId}
385	            />
386	          ) : activeTab === "related" ? (
387	            <RelatedTab conclusionId={id} />
388	          ) : activeTab === "lineage" ? (
389	            <LineagePanel conclusionId={id} />
390	          ) : (
391	            <HistoryTab conclusionId={id} />
392	          )}
393	        </section>
394	
395	        <nav
396	          style={{
397	            marginTop: "2rem",
398	            display: "flex",
399	            alignItems: "center",
400	            gap: "1rem",
401	            flexWrap: "wrap",
402	          }}
403	        >
404	          <Link
405	            href="/knowledge?tab=conclusions"
406	            style={{
407	              fontFamily: "'Cinzel', serif",
408	              fontSize: "0.7rem",
409	              letterSpacing: "0.1em",
410	              color: "var(--parchment-dim)",
411	              textDecoration: "none",
412	            }}
413	          >
414	            ← Knowledge
415	          </Link>
416	          <form action={requestConclusionDeletion}>
417	            <input type="hidden" name="conclusionId" value={id} />
418	            <button
419	              type="submit"
420	              className="btn"
421	              style={{
422	                fontSize: "0.65rem",
423	                color: "var(--ember)",
424	                borderColor: "var(--ember)",
425	              }}
426	            >
427	              Request deletion
428	            </button>
429	          </form>
430	          {sp.deletionRequested && (
431	            <span
432	              style={{
433	                fontSize: "0.7rem",
434	                color: "var(--amber)",
435	              }}
436	            >
437	              Deletion request submitted.
438	            </span>
439	          )}
440	        </nav>
441	      </div>
442	    </main>
443	  );
444	}
445	
446	function ConfidenceContext({ confidence }: { confidence: number }) {
447	  const pct = Math.max(0, Math.min(1, confidence)) * 100;
448	  return (
449	    <div style={{ marginTop: "0.5rem", maxWidth: "30rem" }}>
450	      <div
451	        style={{
452	          display: "flex",
453	          alignItems: "center",
454	          gap: "0.75rem",
455	        }}
456	      >
457	        <div
458	          style={{
459	            width: "12rem",
460	            height: "6px",
461	            background: "var(--border)",
462	            borderRadius: 3,
463	            position: "relative",
464	            overflow: "hidden",
465	          }}
466	        >
467	          <div
468	            style={{
469	              width: `${pct.toFixed(1)}%`,
470	              height: "100%",
471	              background: "var(--gold)",
472	              borderRadius: 3,
473	            }}
474	          />
475	        </div>
476	        <span style={{ fontSize: "0.7rem", color: "var(--parchment-dim)" }}>
477	          {pct.toFixed(0)}%
478	        </span>
479	      </div>
480	      <details style={{ marginTop: "0.35rem" }}>
481	        <summary
482	          style={{
483	            cursor: "pointer",
484	            fontSize: "0.6rem",
485	            color: "var(--parchment-dim)",
486	            letterSpacing: "0.1em",
487	            textTransform: "uppercase",
488	          }}
489	        >
490	          How confidence works
491	        </summary>
492	        <div
493	          style={{
494	            fontSize: "0.75rem",
495	            color: "var(--parchment-dim)",
496	            marginTop: "0.35rem",
497	            lineHeight: 1.6,
498	          }}
499	        >
500	          <p style={{ margin: 0 }}>
501	            Confidence is the system&apos;s assessment of epistemic warrant,
502	            computed from coherence scores, evidence strength, and peer-review
503	            outcomes.
504	          </p>
505	          <p style={{ margin: "0.35rem 0 0" }}>
506	            {TIER_THRESHOLDS.map((t, i) => (
507	              <span key={t.tier}>
508	                <strong style={{ color: t.color }}>
509	                  {t.tier[0].toUpperCase() + t.tier.slice(1)}
510	                </strong>
511	                {t.min > 0 ? ` (≥${(t.min * 100).toFixed(0)}%)` : " (<30%)"}
512	                {i < TIER_THRESHOLDS.length - 1 ? " · " : ""}
513	              </span>
514	            ))}
515	          </p>
516	        </div>
517	      </details>
518	    </div>
519	  );
520	}
521	
522	function PublicationInlinePanel({
523	  canUseReviewControls,
524	  currentFounderId,
525	  firmConclusions,
526	  publishedVersions,
527	  reviews,
528	  sourceUploads,
529	}: {
530	  canUseReviewControls: boolean;
531	  currentFounderId: string;
532	  firmConclusions: Array<{
533	    id: string;
534	    text: string;
535	    topicHint: string;
536	    createdAt: string;
537	    methodologyProfiles: PublicationMethodologyProfile[];
538	  }>;
539	  publishedVersions: Array<{
540	    id: string;
541	    slug: string;
542	    version: number;
543	    publishedAt: string;
544	    doi: string;
545	  }>;
546	  reviews: Array<{
547	    id: string;
548	    status: string;
549	    checklistJson: string;
550	    reviewerNotes: string;
551	    declineReason: string;
552	    revisionAsk: string;
553	    reviewerFounderId: string | null;
554	    createdAt: string;
555	    updatedAt: string;
556	    target: {
557	      id: string;
558	      text: string;
559	      topicHint: string;
560	      confidenceTier: string;
561	      confidence: number;
562	      createdAt: string;
563	      methodologyProfiles: PublicationMethodologyProfile[];
564	    };
565	    reviewer: {
566	      id: string;
567	      displayName: string | null;
568	      name: string;
569	      username: string;
570	    } | null;
571	  }>;
572	  sourceUploads: Array<{
573	    uploadId: string;
574	    title: string;
575	    sourceType: string;
576	    status: string;
577	    visibility: string;
578	    founderId: string;
579	    publishedAt: Date | null;
580	    slug: string | null;
581	  }>;
582	}) {
583	  const latest = publishedVersions[0];
584	
585	  return (
586	    <section
587	      className="portal-card"
588	      style={{
589	        padding: "1rem 1.25rem",
590	        marginBottom: "1rem",
591	        display: "grid",
592	        gap: "0.85rem",
593	      }}
594	    >
595	      <div style={{ display: "flex", justifyContent: "space-between", gap: "1rem", flexWrap: "wrap" }}>
596	        <div>
597	          <h2
598	            className="mono"
599	            style={{
600	              color: "var(--amber-dim)",
601	              fontSize: "0.62rem",
602	              letterSpacing: "0.22em",
603	              margin: 0,
604	              textTransform: "uppercase",
605	            }}
606	          >
607	            Publish state
608	          </h2>
609	          <p style={{ color: "var(--parchment-dim)", fontSize: "0.82rem", margin: "0.35rem 0 0" }}>
610	            Publication review now lives with the conclusion instead of in a separate top-level tab.
611	          </p>
612	        </div>
613	        {latest ? (
614	          <Link
615	            className="btn"
616	            href={`/c/${encodeURIComponent(latest.slug)}/v/${latest.version}`}
617	            style={{ alignSelf: "flex-start", fontSize: "0.65rem", textDecoration: "none" }}
618	          >
619	            Public v{latest.version}
620	          </Link>
621	        ) : null}
622	      </div>
623	
624	      <div style={{ display: "flex", flexWrap: "wrap", gap: "0.7rem", alignItems: "center" }}>
625	        <span className="mono" style={{ color: latest ? "var(--gold)" : "var(--parchment-dim)", fontSize: "0.62rem", letterSpacing: "0.18em", textTransform: "uppercase" }}>
626	          {latest ? `Published ${latest.publishedAt.slice(0, 10)}` : "No published version"}
627	        </span>
628	        {reviews[0] ? (
629	          <span className="mono" style={{ color: "var(--amber-dim)", fontSize: "0.62rem", letterSpacing: "0.18em", textTransform: "uppercase" }}>
630	            Latest review: {reviews[0].status}
631	          </span>
632	        ) : null}
633	      </div>
634	
635	      {publishedVersions.length > 1 ? (
636	        <div style={{ display: "flex", flexWrap: "wrap", gap: "0.45rem" }}>
637	          {publishedVersions.slice(1).map((version) => (
638	            <Link
639	              key={version.id}
640	              href={`/c/${encodeURIComponent(version.slug)}/v/${version.version}`}
641	              style={{ color: "var(--gold-dim)", fontSize: "0.72rem", textDecoration: "none" }}
642	            >
643	              v{version.version}
644	            </Link>
645	          ))}
646	        </div>
647	      ) : null}
648	
649	      {sourceUploads.length > 0 ? (
650	        <div style={{ borderTop: "1px solid var(--border)", paddingTop: "0.85rem" }}>
651	          <h3
652	            className="mono"
653	            style={{
654	              color: "var(--parchment-dim)",
655	              fontSize: "0.58rem",
656	              letterSpacing: "0.2em",
657	              margin: "0 0 0.55rem",
658	              textTransform: "uppercase",
659	            }}
660	          >
661	            Source post visibility
662	          </h3>
663	          <div style={{ display: "grid", gap: "0.5rem" }}>
664	            {sourceUploads.map((source) => (
