1	import type { MqsRecord } from "@/lib/methodologyProfiles";
2	
3	const RADIAL_SIZE = 180;
4	const RADIAL_CENTER = RADIAL_SIZE / 2;
5	const RADIAL_RING = RADIAL_SIZE / 2 - 14;
6	
7	type Axis = {
8	  key: keyof Pick<
9	    MqsRecord,
10	    | "progressivity"
11	    | "severity"
12	    | "aimMethodFit"
13	    | "compressibility"
14	    | "domainSensitivity"
15	  >;
16	  label: string;
17	};
18	
19	const AXES: ReadonlyArray<Axis> = [
20	  { key: "progressivity", label: "Progressivity" },
21	  { key: "severity", label: "Severity" },
22	  { key: "aimMethodFit", label: "Aim–Method Fit" },
23	  { key: "compressibility", label: "Compressibility" },
24	  { key: "domainSensitivity", label: "Domain Sensitivity" },
25	];
26	
27	function pct(n: number) {
28	  return `${Math.round(Math.max(0, Math.min(1, n)) * 100)}%`;
29	}
30	
31	function axisPoint(index: number, total: number, scale: number) {
32	  // Top axis is index 0; rotate clockwise.
33	  const theta = -Math.PI / 2 + (index * 2 * Math.PI) / total;
34	  const x = RADIAL_CENTER + Math.cos(theta) * RADIAL_RING * scale;
35	  const y = RADIAL_CENTER + Math.sin(theta) * RADIAL_RING * scale;
36	  return { x, y };
37	}
38	
39	function radialPolygon(values: number[]): string {
40	  return values
41	    .map((value, idx) => {
42	      const { x, y } = axisPoint(idx, values.length, Math.max(0, Math.min(1, value)));
43	      return `${x.toFixed(2)},${y.toFixed(2)}`;
44	    })
45	    .join(" ");
46	}
47	
48	function evidenceLines(evidence: unknown): string[] {
49	  if (!evidence || typeof evidence !== "object" || Array.isArray(evidence)) return [];
50	  const out: string[] = [];
51	  for (const [key, value] of Object.entries(evidence as Record<string, unknown>)) {
52	    if (value === null || value === undefined) continue;
53	    if (typeof value === "string") {
54	      if (!value.trim()) continue;
55	      out.push(`${key}: ${value.length > 220 ? value.slice(0, 217) + "…" : value}`);
56	    } else if (typeof value === "number" || typeof value === "boolean") {
57	      out.push(`${key}: ${value}`);
58	    } else {
59	      out.push(`${key}: ${JSON.stringify(value).slice(0, 220)}`);
60	    }
61	  }
62	  return out;
63	}
64	
65	export default function MqsCard({ mqs }: { mqs: MqsRecord }) {
66	  const values = AXES.map((a) => Number(mqs[a.key]));
67	
68	  return (
69	    <section
70	      className="portal-card"
71	      aria-labelledby="mqs-card-title"
72	      style={{
73	        padding: "1rem 1.25rem",
74	        marginBottom: "1.5rem",
75	        display: "grid",
76	        gap: "0.85rem",
77	      }}
78	    >
79	      <header style={{ display: "flex", justifyContent: "space-between", flexWrap: "wrap", gap: "0.75rem" }}>
80	        <div>
81	          <h2
82	            className="mono"
83	            id="mqs-card-title"
84	            style={{
85	              color: "var(--amber-dim)",
86	              fontSize: "0.62rem",
87	              letterSpacing: "0.22em",
88	              margin: 0,
89	              textTransform: "uppercase",
90	            }}
91	          >
92	            Methodology Quality Score
93	          </h2>
94	          <p style={{ color: "var(--parchment-dim)", fontSize: "0.78rem", margin: "0.35rem 0 0" }}>
95	            The five working criteria from the meta-method, scored for this conclusion.
96	            Domain sensitivity acts as a gate on the composite.
97	          </p>
98	        </div>
99	        <div style={{ textAlign: "right" }}>
100	          <div style={{ color: "var(--gold)", fontSize: "1.6rem", fontFamily: "'Cinzel', serif" }}>
101	            {pct(mqs.composite)}
102	          </div>
103	          <div className="mono" style={{ fontSize: "0.6rem", color: "var(--parchment-dim)", letterSpacing: "0.18em", textTransform: "uppercase" }}>
104	            Composite
105	          </div>
106	        </div>
107	      </header>
108	
109	      <div style={{ display: "flex", gap: "1.25rem", flexWrap: "wrap", alignItems: "center" }}>
110	        <svg
111	          aria-hidden="true"
112	          height={RADIAL_SIZE}
113	          role="img"
114	          viewBox={`0 0 ${RADIAL_SIZE} ${RADIAL_SIZE}`}
115	          width={RADIAL_SIZE}
116	        >
117	          {[0.25, 0.5, 0.75, 1].map((scale) => (
118	            <polygon
119	              fill="none"
120	              key={`grid-${scale}`}
121	              points={radialPolygon(AXES.map(() => scale))}
122	              stroke="var(--border)"
123	              strokeWidth={0.5}
124	            />
125	          ))}
126	          {AXES.map((axis, idx) => {
127	            const end = axisPoint(idx, AXES.length, 1);
128	            return (
129	              <line
130	                key={`axis-${axis.key}`}
131	                stroke="var(--border)"
132	                strokeWidth={0.5}
133	                x1={RADIAL_CENTER}
134	                x2={end.x}
135	                y1={RADIAL_CENTER}
136	                y2={end.y}
137	              />
138	            );
139	          })}
140	          <polygon
141	            fill="rgba(212, 175, 55, 0.15)"
142	            points={radialPolygon(values)}
143	            stroke="var(--gold)"
144	            strokeWidth={1.25}
145	          />
146	        </svg>
147	
148	        <ul
149	          aria-label="MQS sub-scores"
150	          style={{ listStyle: "none", padding: 0, margin: 0, display: "grid", gap: "0.35rem", minWidth: "12rem" }}
151	        >
152	          {AXES.map((axis) => {
153	            const v = Number(mqs[axis.key]);
154	            return (
155	              <li
156	                key={axis.key}
157	                style={{ display: "flex", justifyContent: "space-between", gap: "1rem", fontSize: "0.82rem" }}
158	              >
159	                <span style={{ color: "var(--parchment)" }}>{axis.label}</span>
160	                <span className="mono" style={{ color: "var(--gold)", letterSpacing: "0.05em" }}>
161	                  {pct(v)}
162	                </span>
163	              </li>
164	            );
165	          })}
166	        </ul>
167	      </div>
168	
169	      <details style={{ borderTop: "1px solid var(--border)", paddingTop: "0.65rem" }}>
170	        <summary
171	          className="mono"
172	          style={{
173	            cursor: "pointer",
174	            color: "var(--parchment-dim)",
175	            fontSize: "0.6rem",
176	            letterSpacing: "0.18em",
177	            textTransform: "uppercase",
178	          }}
179	        >
180	          Evidence (rubric trace)
181	        </summary>
182	        <div style={{ marginTop: "0.5rem", display: "grid", gap: "0.6rem" }}>
183	          {AXES.map((axis) => {
184	            const sub = (mqs.evidence as Record<string, unknown>)[axis.key];
185	            const lines = evidenceLines(sub);
186	            return (
187	              <div key={`evidence-${axis.key}`}>
188	                <h3
189	                  className="mono"
190	                  style={{
191	                    color: "var(--amber-dim)",
192	                    fontSize: "0.55rem",
193	                    letterSpacing: "0.18em",
194	                    margin: 0,
195	                    textTransform: "uppercase",
196	                  }}
197	                >
198	                  {axis.label}
199	                </h3>
200	                {lines.length === 0 ? (
201	                  <p style={{ margin: "0.2rem 0 0", color: "var(--parchment-dim)", fontSize: "0.72rem" }}>
202	                    No evidence recorded.
