1	"use client";
2	
3	import { useMemo, useState } from "react";
4	import {
5	  founderDisplayName,
6	  type FounderDisplayFields,
7	} from "@/lib/founderDisplay";
8	import type { PublicationMethodologyProfile } from "@/lib/methodologyProfiles";
9	
10	type ReviewRow = {
11	  id: string;
12	  status: string;
13	  checklistJson: string;
14	  reviewerNotes: string;
15	  declineReason: string;
16	  revisionAsk: string;
17	  reviewerFounderId: string | null;
18	  createdAt: string;
19	  updatedAt: string;
20	  target: {
21	    id: string;
22	    text: string;
23	    topicHint: string;
24	    confidenceTier: string;
25	    confidence: number;
26	    createdAt: string;
27	    methodologyProfiles: PublicationMethodologyProfile[];
28	  };
29	  reviewer: (FounderDisplayFields & { id: string; username: string }) | null;
30	};
31	
32	type FirmRow = {
33	  id: string;
34	  text: string;
35	  topicHint: string;
36	  createdAt: string;
37	  methodologyProfiles: PublicationMethodologyProfile[];
38	};
39	
40	const CHECKLIST_KEYS = [
41	  ["metaAnalysisOk", "Five-criterion meta-analysis passed"],
42	  ["adversarialEngagedOk", "Top adversarial challenges engaged"],
43	  ["clarityOk", "Publication-ready clarity"],
44	  ["noLeakageOk", "No private-context leakage"],
45	  ["noHarmOk", "No inadvertent harms"],
46	] as const;
47	
48	function methodologyNarrative(profiles: PublicationMethodologyProfile[]): string {
49	  return profiles
50	    .map((profile) => {
51	      const transfer = profile.transferTargets.length ? ` Transfer: ${profile.transferTargets.join("; ")}.` : "";
52	      const risk = profile.failureModes.length ? ` Risk: ${profile.failureModes.join("; ")}.` : "";
53	      return `${profile.title}: ${profile.summary}${transfer}${risk}`;
54	    })
55	    .join("\n\n");
56	}
57	
58	export default function PublicationClient({
59	  reviews,
60	  firmConclusions,
61	  currentFounderId,
62	}: {
63	  reviews: ReviewRow[];
64	  firmConclusions: FirmRow[];
65	  currentFounderId: string;
66	}) {
67	  const [message, setMessage] = useState<string | null>(null);
68	  const [busyId, setBusyId] = useState<string | null>(null);
69	  const [enqueueId, setEnqueueId] = useState<string>(firmConclusions[0]?.id ?? "");
70	  const [openId, setOpenId] = useState<string | null>(reviews[0]?.id ?? null);
71	  const selectedFirm = firmConclusions.find((c) => c.id === enqueueId) ?? null;
72	
73	  const checklistTemplate = useMemo(() => {
74	    const o: Record<string, boolean> = {};
75	    for (const [k] of CHECKLIST_KEYS) o[k] = false;
76	    return o;
77	  }, []);
78	
79	  async function callReview(id: string, body: unknown) {
80	    setBusyId(id);
81	    setMessage(null);
82	    try {
83	      const res = await fetch(`/api/publication/review/${id}`, {
84	        method: "POST",
85	        headers: { "Content-Type": "application/json" },
86	        body: JSON.stringify(body),
87	      });
88	      const json = (await res.json().catch(() => ({}))) as { error?: string };
89	      if (!res.ok) {
90	        setMessage(json.error || `Request failed (${res.status})`);
91	        return;
92	      }
93	      window.location.reload();
94	    } finally {
95	      setBusyId(null);
96	    }
97	  }
98	
99	  async function enqueue() {
100	    if (!enqueueId) return;
101	    setBusyId("enqueue");
102	    setMessage(null);
103	    try {
104	      const res = await fetch("/api/publication/queue", {
105	        method: "POST",
106	        headers: { "Content-Type": "application/json" },
107	        body: JSON.stringify({ conclusionId: enqueueId }),
108	      });
109	      const json = (await res.json().catch(() => ({}))) as { error?: string };
110	      if (!res.ok) {
111	        setMessage(json.error || `Request failed (${res.status})`);
112	        return;
113	      }
114	      window.location.reload();
115	    } finally {
116	      setBusyId(null);
117	    }
118	  }
119	
120	  return (
121	    <div style={{ display: "flex", flexDirection: "column", gap: "1.5rem" }}>
122	      {message ? (
123	        <p style={{ color: "var(--ember)", fontSize: "0.85rem", margin: 0 }} role="status">
124	          {message}
125	        </p>
126	      ) : null}
127	
128	      <section className="portal-card" style={{ padding: "1rem 1.25rem" }}>
129	        <h2 style={{ fontFamily: "'Cinzel', serif", color: "var(--gold)", fontSize: "0.9rem", letterSpacing: "0.12em" }}>
130	          Enqueue firm conclusion
131	        </h2>
132	        <p style={{ color: "var(--parchment-dim)", fontSize: "0.85rem", marginTop: "0.5rem" }}>
133	          Only <strong>firm-tier</strong> conclusions may enter review. Meta-analysis, adversarial engagement, and founder
134	          checklist gates are enforced at publish time.
135	        </p>
136	        <div style={{ display: "flex", flexWrap: "wrap", gap: "0.75rem", marginTop: "0.75rem", alignItems: "center" }}>
137	          <select
138	            className="btn"
139	            style={{ flex: "1 1 320px", background: "var(--obsidian)", color: "var(--parchment)", padding: "0.5rem" }}
140	            value={enqueueId}
141	            onChange={(e) => setEnqueueId(e.target.value)}
142	          >
143	            <option value="">Select a firm conclusion…</option>
144	            {firmConclusions.map((c) => (
145	              <option key={c.id} value={c.id}>
146	                {(c.topicHint ? `${c.topicHint} · ` : "") + c.text.slice(0, 120)}
147	                {c.text.length > 120 ? "…" : ""}
148	              </option>
149	            ))}
150	          </select>
151	          <button type="button" className="btn" disabled={!enqueueId || busyId === "enqueue"} onClick={() => void enqueue()}>
152	            {busyId === "enqueue" ? "Enqueueing…" : "Enqueue"}
153	          </button>
154	          <a className="btn" href="/api/publication/export" style={{ textDecoration: "none", fontSize: "0.65rem" }}>
155	            Export JSON
156	          </a>
157	        </div>
158	        {selectedFirm?.methodologyProfiles.length ? (
159	          <p style={{ color: "var(--parchment-dim)", fontSize: "0.78rem", lineHeight: 1.45, margin: "0.75rem 0 0" }}>
160	            Method profile available: {selectedFirm.methodologyProfiles.map((profile) => profile.title).join("; ")}
161	          </p>
162	        ) : null}
163	      </section>
164	
165	      <section style={{ display: "flex", flexDirection: "column", gap: "0.75rem" }}>
166	        {reviews.map((r) => {
167	          const isMine = r.reviewerFounderId === currentFounderId;
168	          const expanded = openId === r.id;
169	          let checklist: Record<string, boolean> = { ...checklistTemplate };
170	          try {
171	            const parsed = JSON.parse(r.checklistJson || "{}") as Record<string, boolean>;
172	            checklist = { ...checklistTemplate, ...parsed };
173	          } catch {
174	            /* ignore */
175	          }
176	
177	          return (
178	            <article key={r.id} className="portal-card" style={{ padding: "1rem 1.25rem" }}>
179	              <div style={{ display: "flex", justifyContent: "space-between", gap: "1rem", flexWrap: "wrap" }}>
180	                <div style={{ flex: "1 1 420px" }}>
181	                  <div style={{ fontSize: "0.65rem", color: "var(--gold-dim)", textTransform: "uppercase" }}>
182	                    {r.status} · updated {r.updatedAt.slice(0, 10)}
183	                    {r.reviewer
184	                      ? ` · reviewer ${founderDisplayName(r.reviewer)}`
185	                      : ""}
186	                  </div>
187	                  <p style={{ marginTop: "0.5rem", color: "var(--parchment)" }}>{r.target.text}</p>
188	                  {r.revisionAsk ? (
189	                    <p style={{ marginTop: "0.35rem", fontSize: "0.8rem", color: "var(--ember)" }}>
190	                      Revision ask: {r.revisionAsk}
191	                    </p>
192	                  ) : null}
193	                  {r.declineReason ? (
194	                    <p style={{ marginTop: "0.35rem", fontSize: "0.8rem", color: "var(--ember)" }}>
195	                      Declined: {r.declineReason}
196	                    </p>
197	                  ) : null}
198	                </div>
199	                <div style={{ display: "flex", flexDirection: "column", gap: "0.35rem", alignItems: "flex-start" }}>
200	                  <button type="button" className="btn" style={{ fontSize: "0.65rem" }} onClick={() => setOpenId(expanded ? null : r.id)}>
201	                    {expanded ? "Hide actions" : "Actions"}
202	                  </button>
203	                </div>
204	              </div>
205	
206	              {expanded ? (
207	                <div style={{ marginTop: "1rem", borderTop: "1px solid var(--border)", paddingTop: "1rem" }}>
208	                  <div style={{ display: "flex", flexWrap: "wrap", gap: "0.5rem" }}>
209	                    {(r.status === "queued" || r.status === "needs_revision") && (
210	                      <button
211	                        type="button"
212	                        className="btn"
213	                        disabled={busyId === r.id}
214	                        onClick={() => void callReview(r.id, { action: "claim" })}
215	                      >
216	                        {busyId === r.id ? "…" : "Claim review"}
217	                      </button>
218	                    )}
219	                    {r.status === "in_review" && isMine && (
220	                      <button
221	                        type="button"
222	                        className="btn"
223	                        disabled={busyId === r.id}
224	                        onClick={() => void callReview(r.id, { action: "release" })}
225	                      >
226	                        Release claim
227	                      </button>
228	                    )}
229	                  </div>
230	
231	                  {r.status === "in_review" && isMine ? (
232	                    <PublishPanel
233	                      key={r.id}
234	                      reviewId={r.id}
235	                      checklist={checklist}
236	                      defaultStatedConfidence={r.target.confidence}
237	                      suggestedMethodologyProfiles={r.target.methodologyProfiles}
238	                      busy={busyId === r.id}
239	                      onError={(msg) => setMessage(msg)}
240	                      onPublish={(payload) => void callReview(r.id, payload)}
241	                      onNeedsRevision={(revisionAsk) => void callReview(r.id, { action: "needs_revision", revisionAsk })}
242	                      onDecline={(declineReason) => void callReview(r.id, { action: "decline", declineReason })}
243	                      onSaveChecklist={(next) => void callReview(r.id, { action: "checklist", checklist: next })}
244	                    />
245	                  ) : null}
246	                </div>
247	              ) : null}
248	            </article>
249	          );
250	        })}
251	      </section>
252	    </div>
253	  );
254	}
255	
256	function PublishPanel({
257	  reviewId,
258	  checklist,
259	  defaultStatedConfidence,
260	  suggestedMethodologyProfiles,
261	  busy,
262	  onError,
263	  onPublish,
264	  onNeedsRevision,
265	  onDecline,
266	  onSaveChecklist,
267	}: {
268	  reviewId: string;
269	  checklist: Record<string, boolean>;
270	  defaultStatedConfidence: number;
271	  suggestedMethodologyProfiles: PublicationMethodologyProfile[];
272	  busy: boolean;
273	  onError: (msg: string) => void;
274	  onPublish: (payload: unknown) => void;
275	  onNeedsRevision: (ask: string) => void;
276	  onDecline: (reason: string) => void;
277	  onSaveChecklist: (next: Record<string, boolean>) => void;
278	}) {
279	  const [localCheck, setLocalCheck] = useState(checklist);
280	  const [evidenceSummary, setEvidenceSummary] = useState("");
281	  const [exitLines, setExitLines] = useState("");
282	  const [objection, setObjection] = useState("");
283	  const [firmAnswer, setFirmAnswer] = useState("");
284	  const [openQs, setOpenQs] = useState("");
285	  const [voices, setVoices] = useState("");
286	  const [methodText, setMethodText] = useState(() => methodologyNarrative(suggestedMethodologyProfiles));
287	  const [discounted, setDiscounted] = useState("0.65");
288	  const [calibReason, setCalibReason] = useState("");
289	  const [slug, setSlug] = useState("");
290	  const [revisionAsk, setRevisionAsk] = useState("");
291	  const [declineReason, setDeclineReason] = useState("");
292	
293	  return (
294	    <div style={{ marginTop: "1rem", display: "flex", flexDirection: "column", gap: "0.75rem" }}>
295	      <fieldset style={{ border: "1px solid var(--border)", padding: "0.75rem" }}>
296	        <legend style={{ color: "var(--gold-dim)", fontSize: "0.65rem", letterSpacing: "0.12em" }}>Publication checklist</legend>
297	        <div style={{ display: "grid", gap: "0.35rem" }}>
298	          {CHECKLIST_KEYS.map(([k, label]) => (
299	            <label key={k} style={{ color: "var(--parchment-dim)", fontSize: "0.8rem", display: "flex", gap: "0.5rem" }}>
300	              <input
301	                type="checkbox"
302	                checked={Boolean(localCheck[k])}
303	                onChange={(e) => setLocalCheck((prev) => ({ ...prev, [k]: e.target.checked }))}
304	              />
305	              {label}
306	            </label>
307	          ))}
308	        </div>
309	        <button type="button" className="btn" style={{ marginTop: "0.5rem", fontSize: "0.65rem" }} disabled={busy} onClick={() => onSaveChecklist(localCheck)}>
310	          Save checklist draft
311	        </button>
312	      </fieldset>
313	
314	      <label style={{ color: "var(--parchment-dim)", fontSize: "0.8rem", display: "flex", flexDirection: "column", gap: "0.35rem" }}>
315	        Evidence summary (public)
316	        <textarea
317	          value={evidenceSummary}
318	          onChange={(e) => setEvidenceSummary(e.target.value)}
319	          rows={4}
320	          style={{ width: "100%", background: "var(--obsidian)", color: "var(--parchment)", padding: "0.5rem" }}
321	        />
322	      </label>
323	
324	      <label style={{ color: "var(--parchment-dim)", fontSize: "0.8rem", display: "flex", flexDirection: "column", gap: "0.35rem" }}>
325	        Exit conditions / what would change our mind (one per line)
326	        <textarea
327	          value={exitLines}
328	          onChange={(e) => setExitLines(e.target.value)}
329	          rows={4}
330	          style={{ width: "100%", background: "var(--obsidian)", color: "var(--parchment)", padding: "0.5rem" }}
331	        />
332	      </label>
333	
334	      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "0.75rem" }}>
335	        <label style={{ color: "var(--parchment-dim)", fontSize: "0.8rem", display: "flex", flexDirection: "column", gap: "0.35rem" }}>
336	          Strongest engaged objection
337	          <textarea
338	            value={objection}
339	            onChange={(e) => setObjection(e.target.value)}
340	            rows={4}
341	            style={{ width: "100%", background: "var(--obsidian)", color: "var(--parchment)", padding: "0.5rem" }}
342	          />
343	        </label>
344	        <label style={{ color: "var(--parchment-dim)", fontSize: "0.8rem", display: "flex", flexDirection: "column", gap: "0.35rem" }}>
345	          Firm answer
346	          <textarea
347	            value={firmAnswer}
348	            onChange={(e) => setFirmAnswer(e.target.value)}
349	            rows={4}
350	            style={{ width: "100%", background: "var(--obsidian)", color: "var(--parchment)", padding: "0.5rem" }}
351	          />
352	        </label>
353	      </div>
354	
355	      <label style={{ color: "var(--parchment-dim)", fontSize: "0.8rem", display: "flex", flexDirection: "column", gap: "0.35rem" }}>
356	        Adjacent open questions (one per line)
357	        <textarea
358	          value={openQs}
359	          onChange={(e) => setOpenQs(e.target.value)}
360	          rows={3}
361	          style={{ width: "100%", background: "var(--obsidian)", color: "var(--parchment)", padding: "0.5rem" }}
362	        />
363	      </label>
364	
365	      <label style={{ color: "var(--parchment-dim)", fontSize: "0.8rem", display: "flex", flexDirection: "column", gap: "0.35rem" }}>
366	        Voice map (optional) — one per line, e.g. “Habermas: agrees on X; diverges on Y”.
367	        <textarea
368	          value={voices}
369	          onChange={(e) => setVoices(e.target.value)}
370	          rows={3}
371	          style={{ width: "100%", background: "var(--obsidian)", color: "var(--parchment)", padding: "0.5rem" }}
372	        />
373	      </label>
374	
375	      <fieldset style={{ border: "1px solid var(--border)", padding: "0.75rem" }}>
376	        <legend style={{ color: "var(--gold-dim)", fontSize: "0.65rem", letterSpacing: "0.12em" }}>
377	          Methodology analysis
378	        </legend>
379	        {suggestedMethodologyProfiles.length ? (
380	          <div style={{ display: "grid", gap: "0.55rem", marginBottom: "0.7rem" }}>
381	            {suggestedMethodologyProfiles.map((profile) => (
382	              <div key={profile.patternType} style={{ borderLeft: "2px solid var(--gold-dim)", paddingLeft: "0.65rem" }}>
383	                <strong style={{ color: "var(--parchment)", display: "block", fontSize: "0.82rem" }}>
384	                  {profile.title}
385	                </strong>
386	                <span style={{ color: "var(--parchment-dim)", display: "block", fontSize: "0.76rem", lineHeight: 1.45 }}>
387	                  {profile.summary}
388	                </span>
389	              </div>
390	            ))}
391	          </div>
392	        ) : null}
393	        <label style={{ color: "var(--parchment-dim)", fontSize: "0.8rem", display: "flex", flexDirection: "column", gap: "0.35rem" }}>
394	          Public method narrative
395	          <textarea
396	            value={methodText}
397	            onChange={(e) => setMethodText(e.target.value)}
398	            rows={5}
399	            style={{ width: "100%", background: "var(--obsidian)", color: "var(--parchment)", padding: "0.5rem" }}
400	          />
401	        </label>
402	      </fieldset>
403	
404	      <div style={{ display: "flex", flexWrap: "wrap", gap: "0.75rem" }}>
405	        <label style={{ color: "var(--parchment-dim)", fontSize: "0.8rem", display: "flex", flexDirection: "column", gap: "0.35rem" }}>
406	          Discounted confidence (0–1)
407	          <input
408	            value={discounted}
