410	            style={{ background: "var(--obsidian)", color: "var(--parchment)", padding: "0.5rem" }}
411	          />
412	        </label>
413	        <label style={{ color: "var(--parchment-dim)", fontSize: "0.8rem", display: "flex", flexDirection: "column", gap: "0.35rem" }}>
414	          Optional slug override
415	          <input
416	            value={slug}
417	            onChange={(e) => setSlug(e.target.value)}
418	            style={{ background: "var(--obsidian)", color: "var(--parchment)", padding: "0.5rem", minWidth: "240px" }}
419	          />
420	        </label>
421	      </div>
422	
423	      <label style={{ color: "var(--parchment-dim)", fontSize: "0.8rem", display: "flex", flexDirection: "column", gap: "0.35rem" }}>
424	        Calibration discount reason (why headline confidence differs from stated)
425	        <textarea
